<template><div class="page-container auth-page"><form class="glass-panel auth-card" @submit.prevent="submit"><h1>Create account</h1><input v-model="username" placeholder="Username" /><input v-model="displayName" placeholder="Display name" /><input v-model="email" type="email" placeholder="Email" /><input v-model="password" type="password" placeholder="Password" /><button class="submit">Register</button></form></div></template><script setup lang="ts">import { ref } from 'vue'; import { useRouter } from 'vue-router'; import { useAuthStore } from '@/stores/auth'; const username = ref('louisdo'); const displayName = ref('Louis Do'); const email = ref('louis@example.com'); const password = ref('SecurePass123!'); const auth = useAuthStore(); const router = useRouter(); async function submit() { await auth.register({ username: username.value, displayName: displayName.value, email: email.value, password: password.value }); await router.push('/'); }</script><style scoped>.auth-page{display:grid;place-items:center;min-height:100vh}.auth-card{width:min(30rem,100%);padding:var(--space-8);display:grid;gap:var(--space-4)}input,.submit{padding:1rem;border-radius:var(--radius-lg);border:1px solid var(--input-border);background:var(--input-bg);color:var(--text-primary)}.submit{background:var(--accent-teal);color:var(--bg-primary);font-weight:var(--font-weight-semibold)}</style>